final:
module RefModule (
    input clk,
    input reset,
    input enable,
    output reg [7:0] q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            q <= 8'b00000001;
        else if (enable)
            q <= {q[6:0], ~q[7]};
    end

endmodule
